
-- Banking SQL test dataset for SQL Server
-- Includes a few intentional data quality issues for cleaning exercises

IF OBJECT_ID('dbo.fact_transactions', 'U') IS NOT NULL DROP TABLE dbo.fact_transactions;
IF OBJECT_ID('dbo.fact_loans', 'U') IS NOT NULL DROP TABLE dbo.fact_loans;
IF OBJECT_ID('dbo.dim_accounts', 'U') IS NOT NULL DROP TABLE dbo.dim_accounts;
IF OBJECT_ID('dbo.dim_customers', 'U') IS NOT NULL DROP TABLE dbo.dim_customers;

CREATE TABLE dbo.dim_customers (
    Customer_ID INT PRIMARY KEY,
    First_Name NVARCHAR(50),
    Last_Name NVARCHAR(50),
    Gender CHAR(1),
    Birth_Date DATE,
    City NVARCHAR(50),
    Customer_Segment NVARCHAR(20),
    Join_Date DATE,
    Status NVARCHAR(20)
);

CREATE TABLE dbo.dim_accounts (
    Account_ID INT PRIMARY KEY,
    Customer_ID INT,
    Account_Type NVARCHAR(20),
    Open_Date DATE,
    Close_Date DATE NULL,
    Currency CHAR(3),
    Account_Status NVARCHAR(20),
    FOREIGN KEY (Customer_ID) REFERENCES dbo.dim_customers(Customer_ID)
);

CREATE TABLE dbo.fact_transactions (
    Transaction_ID INT PRIMARY KEY,
    Account_ID INT,
    Transaction_Date DATE,
    Transaction_Type NVARCHAR(30),
    Amount DECIMAL(12,2),
    Direction NVARCHAR(10),
    Merchant_Category NVARCHAR(50),
    Channel NVARCHAR(20),
    City NVARCHAR(50),
    Is_Fraud_Flag BIT,
    FOREIGN KEY (Account_ID) REFERENCES dbo.dim_accounts(Account_ID)
);

CREATE TABLE dbo.fact_loans (
    Loan_ID INT PRIMARY KEY,
    Customer_ID INT,
    Loan_Type NVARCHAR(20),
    Loan_Amount DECIMAL(14,2),
    Interest_Rate DECIMAL(5,2),
    Start_Date DATE,
    End_Date DATE,
    Loan_Status NVARCHAR(20),
    Monthly_Installment DECIMAL(12,2),
    FOREIGN KEY (Customer_ID) REFERENCES dbo.dim_customers(Customer_ID)
);


